# 문제: 여러 명의 성적을 입력받아 통계 내기
# 설계: 1) 데이터 수집  2) 평균 계산  3) 등급 판정  4) 결과 출력
# 이렇게 단계를 나누면 각 단계를 함수로 구현하기 쉬워진다

def collect_scores(pairs):
    return {name: score for name, score in pairs}

def average(scores):
    return sum(scores.values()) / len(scores)

def grade_of(avg):
    if avg >= 90: return "A"
    if avg >= 80: return "B"
    if avg >= 70: return "C"
    return "D"

data = [("철수", 85), ("영희", 92), ("민수", 78)]
scores = collect_scores(data)
avg = average(scores)
print(f"평균: {avg:.1f}, 학급 등급: {grade_of(avg)}")
for name, score in scores.items():
    print(f"  {name}: {score}점 ({grade_of(score)})")
